const crypto = require('crypto');
const fs = require('fs');
const path = require('path');

const input = $input.first().json;

function safeSlug(value) {
  return String(value || 'job')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '')
    .slice(0, 60) || 'job';
}

function nowStamp() {
  return new Date().toISOString().replace(/[-:]/g, '').replace(/\.\d{3}Z$/, 'Z');
}

const required = ['idea', 'targetAudience'];
const missing = required.filter((field) => !input[field]);
if (missing.length > 0) {
  throw new Error(`Missing required field(s): ${missing.join(', ')}`);
}

const jobId = `${safeSlug(input.project)}-${nowStamp()}-${crypto.randomBytes(3).toString('hex')}`;
const createdAt = input.createdAt || new Date().toISOString();
const jobDir = $env.NVF_JOB_DIR || '/media/scripts';

const job = {
  schemaVersion: '1.0.0',
  jobId,
  project: input.project,
  type: input.type || 'short-video',
  pillar: input.pillar,
  idea: input.idea,
  targetAudience: input.targetAudience,
  cta: input.cta,
  status: 'needs-review',
  requiresHumanReview: true,
  autoPublish: false,
  createdAt,
  updatedAt: createdAt,
  source: {
    system: 'n8n',
    workflow: 'NVF 01 - GPT Video Request Intake',
    endpoint: '/webhook/nvf-video-request'
  },
  review: { decision: 'pending', reviewer: null, reviewedAt: null, notes: null },
  script: { hook: null, body: null, cta: null, caption: null, hashtags: [] },
  render: { status: 'not-started', format: 'vertical-9x16', durationTargetSeconds: 30, outputPath: null },
  publish: { status: 'not-ready', manualOnly: true, platforms: [], publishedAt: null }
};

fs.mkdirSync(jobDir, { recursive: true });
const filePath = path.join(jobDir, `${jobId}.json`);
fs.writeFileSync(filePath, JSON.stringify(job, null, 2), 'utf8');

return [{ json: { ok: true, jobId, filePath, status: job.status, job } }];
